"use client";

import { useEffect, useState, useRef, useCallback } from "react";
import { getSupabaseBrowser } from "@/lib/supabase";
import type { RealtimeChannel } from "@supabase/supabase-js";
import type { RosarySnapshot, RosaryParticipant, ConnectionState } from "@/lib/devotions/types";

const HEARTBEAT_INTERVAL = 25_000;
const MAX_PARTICIPANTS = 50;

export function useRosarioSync({
  programId,
  profileId,
  displayName,
  onStepChange,
  onParticipantsChange,
}: {
  programId: string;
  profileId: string;
  displayName: string;
  onStepChange?: (stepIndex: number) => void;
  onParticipantsChange?: (participants: RosaryParticipant[]) => void;
}): {
  participants: RosaryParticipant[];
  currentStepIndex: number;
  isConnected: boolean;
  connectionState: ConnectionState;
  sendResponse: () => void;
  sendChatMessage: (text: string) => void;
  repeatIteration: number;
  repeatTotal: number;
} {
  const [participants, setParticipants] = useState<RosaryParticipant[]>([]);
  const [snapshot, setSnapshot] = useState<RosarySnapshot | null>(null);
  const [connectionState, setConnectionState] = useState<ConnectionState>("connecting");
  const [isConnected, setIsConnected] = useState(false);

  const channelRef = useRef<RealtimeChannel | null>(null);
  const heartbeatRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const reconnectAttemptsRef = useRef(0);
  const reconnectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const supabase = getSupabaseBrowser();
  const sessionIdRef = useRef<string>(programId);

  const clearTimers = useCallback(() => {
    if (heartbeatRef.current) clearInterval(heartbeatRef.current);
    if (reconnectTimerRef.current) clearTimeout(reconnectTimerRef.current);
    heartbeatRef.current = null;
    reconnectTimerRef.current = null;
  }, []);

  const closeChannel = useCallback(() => {
    if (channelRef.current && supabase) {
      supabase.removeChannel(channelRef.current);
      channelRef.current = null;
    }
  }, [supabase]);

  const fetchSnapshot = useCallback(async (): Promise<RosarySnapshot | null> => {
    try {
      const res = await fetch(`/api/rosario/snapshot?programId=${encodeURIComponent(programId)}`);
      if (!res.ok) return null;
      const data = await res.json();
      return data as RosarySnapshot;
    } catch {
      return null;
    }
  }, [programId]);

  const applySnapshot = useCallback((snap: RosarySnapshot | null) => {
    if (!snap) return;
    setSnapshot(snap);
    setParticipants(snap.participants);
    setConnectionState("connected");
    setIsConnected(true);
    reconnectAttemptsRef.current = 0;
    onParticipantsChange?.(snap.participants);
    onStepChange?.(snap.stepId ? 0 : 0);
  }, [onParticipantsChange, onStepChange]);

  const connect = useCallback(async () => {
    if (!supabase) {
      await applySnapshot(await createLocalSnapshot());
      return;
    }

    if (channelRef.current) {
      closeChannel();
    }

    setConnectionState("connecting");

    try {
      const initial = await fetchSnapshot();
      await applySnapshot(initial);

      const channel = supabase.channel(`session:${sessionIdRef.current}`, {
        config: { presence: { key: profileId } },
      });

      channel
        .on("presence", { event: "sync" }, () => {
          const state = channel.presenceState();
          const users: RosaryParticipant[] = [];
          Object.values(state).forEach((entries: unknown) => {
            const list = entries as RosaryParticipant[];
            users.push(...list);
          });
          setParticipants(users);
          onParticipantsChange?.(users);
        })
        .on("broadcast", { event: "snapshot" }, (payload) => {
          applySnapshot(payload.snapshot as RosarySnapshot);
        })
        .subscribe(async (status) => {
          if (status === "SUBSCRIBED") {
            await channel.track({
              id: profileId,
              displayName,
              isResponding: false,
            });
            setIsConnected(true);
            setConnectionState("connected");
            reconnectAttemptsRef.current = 0;
          } else {
            setIsConnected(false);
            setConnectionState("reconnecting");
          }
        });

      channelRef.current = channel;
    } catch {
      setConnectionState("reconnecting");
    }
  }, [supabase, profileId, displayName, applySnapshot, closeChannel, onParticipantsChange, onStepChange]);

  const createLocalSnapshot = async (): Promise<RosarySnapshot | null> => {
    try {
      const initial = await fetchSnapshot();
      if (initial) return initial;
    } catch {}
    return null;
  };

  const sendResponse = useCallback(() => {
    if (!snapshot) return;
    const eventId = crypto.randomUUID();
    fetch("/api/rosario/transition", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        sessionId: snapshot.sessionId,
        eventId,
        sessionVersion: snapshot.sessionVersion,
        stepInstanceId: snapshot.stepInstanceId,
        eventType: "HOLD_END",
        participantId: profileId,
      }),
    }).then(async (res) => {
      if (!res.ok) return;
      const data = await res.json();
      if (data.snapshot) {
        applySnapshot(data.snapshot);
      }
    });
  }, [snapshot, profileId, applySnapshot]);

  const sendChatMessage = useCallback(
    (text: string) => {
      if (!channelRef.current || !text.trim()) return;
      channelRef.current.send({
        type: "broadcast",
        event: "chat",
        payload: { message: { id: crypto.randomUUID(), displayName, text: text.trim(), createdAt: new Date().toISOString() } },
      });
    },
    [displayName]
  );

  useEffect(() => {
    if (!supabase) {
      applySnapshot(null);
      setConnectionState("offline");
      return;
    }

    void connect();

    heartbeatRef.current = setInterval(async () => {
      try {
        await fetch("/api/rosario/heartbeat", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ profileId, displayName }),
        });
      } catch {
        /* ignorar */
      }
    }, HEARTBEAT_INTERVAL);

    return () => {
      clearTimers();
      closeChannel();
      setIsConnected(false);
    };
  }, [supabase, profileId, displayName, connect, clearTimers, closeChannel, applySnapshot]);

  return {
    participants,
    currentStepIndex: snapshot ? 0 : 0,
    isConnected,
    connectionState,
    sendResponse,
    sendChatMessage,
    repeatIteration: snapshot?.repeatIteration ?? 1,
    repeatTotal: snapshot?.repeatTotal ?? 10,
  };
}
